import 'dart:typed_data';
import 'dart:convert';

void main() {
  final hex = "";
  
  final bytes = <int>[];
  for (int i = 0; i < hex.length; i += 2) {
    bytes.add(int.parse(hex.substring(i, i + 2), radix: 16));
  }
  
  final str = String.fromCharCodes(bytes);
  print("String: $str");
  
  final matches = RegExp(r'content/[a-zA-Z0-9-]+').allMatches(str);
  print("Matches: ${matches.length}");
  for (final m in matches) {
    print(m.group(0));
  }

  // test UUID match
  final uuidMatches = RegExp(r'[a-f0-9]{8}-[a-f0-9]{4}-[a-f0-9]{4}-[a-f0-9]{4}-[a-f0-9]{12}').allMatches(str);
  print("UUID Matches: ${uuidMatches.length}");
  for (final m in uuidMatches) {
    print(m.group(0));
  }
}
